class Solution {
public:
    bool uniqueOccurrences(vector<int>& arr) {
        unordered_map<int, int> count;
        for (int num : arr) {
            count[num]++;
        }
        unordered_set<int> occurrences;
        for (auto& pair : count) {
            if (occurrences.find(pair.second) != occurrences.end()) {
                return false;
            }
            occurrences.insert(pair.second);
        }
        return true;
    }
};
